'use client'

import { useRef, useState } from 'react'
import { useRouter } from 'next/navigation'
import { toast } from 'sonner'
import { Button } from '@/components/ui/button'

export function ImportUploadForm() {
    const router = useRouter()
    const fileInputRef = useRef<HTMLInputElement>(null)
    const [selectedFile, setSelectedFile] = useState<File | null>(null)
    const [loading, setLoading] = useState(false)

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0] ?? null
        setSelectedFile(file)
    }

    const handleUpload = async () => {
        if (!selectedFile) return

        setLoading(true)
        try {
            const formData = new FormData()
            formData.append('file', selectedFile)

            const res = await fetch('/api/import/jobs', {
                method: 'POST',
                body: formData,
            })

            if (!res.ok) {
                const data = await res.json().catch(() => ({}))
                throw new Error((data as { error?: string }).error ?? '업로드에 실패했습니다')
            }

            toast.success('Import가 시작되었습니다')
            setSelectedFile(null)
            if (fileInputRef.current) fileInputRef.current.value = ''
            router.refresh()
        } catch (err) {
            console.error('[ImportUploadForm] upload error:', err)
            toast.error(err instanceof Error ? err.message : '업로드 중 오류가 발생했습니다')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="flex items-center gap-3 p-4 border rounded-lg bg-slate-50">
            <input
                ref={fileInputRef}
                type="file"
                accept=".csv,.xlsx"
                onChange={handleFileChange}
                className="text-sm text-slate-600 file:mr-3 file:py-1.5 file:px-3 file:rounded file:border-0 file:text-sm file:font-medium file:bg-white file:text-slate-700 file:cursor-pointer hover:file:bg-slate-100"
            />
            <Button
                onClick={handleUpload}
                disabled={!selectedFile || loading}
            >
                {loading ? '업로드 중...' : '업로드'}
            </Button>
        </div>
    )
}

