'use client'

import { format } from 'date-fns'
import type { ColDef, ValueFormatterParams } from 'ag-grid-community'
import { DataTable } from '@/components/ui/data-table'
import { Badge } from '@/components/ui/badge'
import type { ImportJobItem } from '@/features/import/types'

interface ImportJobTableProps {
    items: ImportJobItem[]
}

type StatusVariant = 'default' | 'destructive' | 'secondary' | 'outline'

const STATUS_MAP: Record<ImportJobItem['status'], { label: string; variant: StatusVariant }> = {
    DONE: { label: '완료', variant: 'default' },
    FAILED: { label: '실패', variant: 'destructive' },
    RUNNING: { label: '진행중', variant: 'secondary' },
    PENDING: { label: '대기', variant: 'outline' },
}

function StatusBadge({ value }: { value: ImportJobItem['status'] }) {
    const { label, variant } = STATUS_MAP[value] ?? { label: value, variant: 'outline' }
    return <Badge variant={variant}>{label}</Badge>
}

const columnDefs: ColDef<ImportJobItem>[] = [
    { field: 'id', headerName: '번호', width: 80 },
    { field: 'fileName', headerName: '파일명', flex: 1 },
    {
        field: 'status',
        headerName: '상태',
        width: 100,
        cellRenderer: (params: { value: ImportJobItem['status'] }) => (
            <StatusBadge value={params.value} />
        ),
    },
    {
        headerName: '처리 현황',
        width: 120,
        valueGetter: (params) => {
            const data = params.data
            if (!data) return ''
            return `${data.doneCount} / ${data.totalCount}`
        },
    },
    {
        field: 'createdAt',
        headerName: '요청일시',
        width: 150,
        valueFormatter: (params: ValueFormatterParams<ImportJobItem, Date>) =>
            params.value ? format(new Date(params.value), 'yyyy-MM-dd HH:mm') : '',
    },
]

export function ImportJobTable({ items }: ImportJobTableProps) {
    return (
        <DataTable<ImportJobItem>
            columnDefs={columnDefs}
            rowData={items}
        />
    )
}

